using Microsoft.EntityFrameworkCore;

// Cosmos DB project context — migrated to EF Core 9
class CosmosDbContext : DbContext
{
    public DbSet<Session> Sessions => Set<Session>();

    protected override void OnConfiguring(DbContextOptionsBuilder options)
    {
        options.UseCosmos(
            "https://localhost:8081",
            "C2y6yDjf5/R+ob0N8A7Cgv30VRDJIWEHLM+4QDU5DE2nQ9nDuVTqobD4b8mGGyPMbIZnqyMsEcaGQy67XIw/Jw==",
            "AppDb");
    }

    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        // Breaking change: Default discriminator property renamed from "Discriminator" to "$type".
        // Preserve "Discriminator" to remain compatible with existing documents.
        modelBuilder.Entity<Session>().HasDiscriminator<string>("Discriminator");

        // Breaking change: id property no longer contains the discriminator value.
        // Preserve old compound id format ("Session|<key>") for existing documents.
        modelBuilder.Entity<Session>().HasRootDiscriminatorInJsonId(true);
    }
}

class Session
{
    public string Id { get; set; } = string.Empty;
    public string Name { get; set; } = string.Empty;
}

// Breaking change: Cosmos DB provider no longer supports synchronous I/O.
// All sync calls (ToList, SaveChanges, etc.) now throw.
// Use async equivalents instead.
class CosmosRepository
{
    private readonly CosmosDbContext _db;
    public CosmosRepository(CosmosDbContext db) => _db = db;

    // BEFORE (breaks in EF Core 9):
    //   var sessions = _db.Sessions.ToList();
    //   _db.SaveChanges();

    // AFTER — use async:
    public async Task<List<Session>> GetAllAsync()
        => await _db.Sessions.ToListAsync();

    public async Task AddAsync(Session session)
    {
        _db.Sessions.Add(session);
        await _db.SaveChangesAsync();
    }
}

